+        ? Set<ReplaceRecur<TSetValue, TWrapped, TType>>
+        : TValue extends readonly unknown[]
+          ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TWrapped, TType> }
+          : TValue extends object
+            ? {
+                [TKey in keyof TValue]: ReplaceRecur<
+                  TValue[TKey],
+                  TWrapped,
+                  TType
+                >;
+              }
+            : TValue;
