+/**
+ * Infers the recursive input type of a wrapped schema.
+ */
+export type RecursiveInput<
+  TWrapped extends
+    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
+    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+> = ReplaceRecur<InferInput<TWrapped>, TWrapped, 'input'>;
+
+/**
