+  readonly reference: typeof recursive;
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Recursive schema async interface.
+ */
+export interface RecursiveSchemaAsync<
+  TWrapped extends
+    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
+    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchemaAsync<
+    RecursiveInput<TWrapped>,
+    RecursiveOutput<TWrapped>,
+    InferIssue<TWrapped>
+  > {
+  /**
+   * The schema type.
+   */
+  readonly type: 'recursive';
+  /**
+   * The schema reference.
+   */
+  readonly reference: typeof recursiveAsync;
+  /**
+   * The wrapped schema.
+   */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Placeholder for a self reference within a recursive schema.
+ */
+export const Recur: RecurSchema = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recursive,
+  expects: 'unknown',
+  async: false,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'() {
+    throw new Error('Recur must be wrapped with recursive or recursiveAsync.');
+  },
+};
+
+function _resolveRecur<TValue>(value: TValue, recur: unknown): TValue {
+  if (value === Recur) {
+    return recur as TValue;
+  }
+  if (!value || typeof value !== 'object') {
+    return value;
+  }
+
+  const references = new WeakMap<object, object>();
+  const resolve = (input: object): object => {
+    const reference = references.get(input);
+    if (reference) {
+      return reference;
+    }
+    const output = Array.isArray(input)
+      ? []
+      : Object.create(Object.getPrototypeOf(input));
+    references.set(input, output);
+    for (const key of Reflect.ownKeys(input)) {
+      const descriptor = Object.getOwnPropertyDescriptor(input, key)!;
+      if ('value' in descriptor) {
+        descriptor.value =
+          descriptor.value === Recur
+            ? recur
+            : descriptor.value && typeof descriptor.value === 'object'
+              ? resolve(descriptor.value)
+              : descriptor.value;
+      }
+      Object.defineProperty(output, key, descriptor);
+    }
+    return output;
+  };
+  return resolve(value) as TValue;
+}
+
+/**
+ * Creates a recursive schema by resolving `Recur` placeholders.
+ *
+ * @param wrapped The schema containing recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+>(wrapped: TWrapped): RecursiveSchema<TWrapped> {
+  let schema: RecursiveSchema<TWrapped>;
+  const resolved = _resolveRecur(wrapped, {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false,
+    get wrapped() {
+      return resolved;
+    },
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
+      return resolved['~run'](dataset, config);
+    },
+  });
+  schema = {
+    kind: 'schema',
+    type: 'recursive',
+    reference: recursive,
+    expects: wrapped.expects,
+    async: false,
+    wrapped: resolved,
+    get '~standard'() {
+      return _getStandardProps(this);
+    },
+    '~run'(dataset, config) {
+      return this.wrapped['~run'](dataset, config);
+    },
+  } as RecursiveSchema<TWrapped>;
+  return schema;
+}
